INSERT INTO public.photos VALUES (23732, 'Av. de Navarra 1980', 'Imagen centrada parcialmente en la gran explanada de acceso (que incluâ”œآ،a â”œأ­rboles) a la original estaciâ”œâ”‚n del ferrocarril Central de Aragâ”œâ”‚n o Caminreal, luego Zaragoza-Delicias. Los andenes y vâ”œآ،as quedaban en las traseras del referencial edificio diseâ”œâ–’ado por el arquitecto Luis Gutiâ”œآ®rrez Soto. Justo a la derecha, fuera de plano, se localizaba el Campo de Deportes Renfe "Delicias" para prâ”œأ­ctica del balompiâ”œآ®. Fuente visual: AMZ.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38492538825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38492538825.webp', 'https://www.flickr.com/photos/zaragozaantigua/38492538825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23734, 'Hostal y garaje Oroel c.1962', 'Imagen capturada desde cierta altura en la avenida de Navarra y centrada en el moderno hostal y garaje Oroel, ubicados en el nâ”¬â•‘ 50 de la avenida, cuando los accesos, la acera y la calzada aâ”œâ•‘n no habâ”œآ،an sido urbanizadas convenientemente. A la izquierda, vista parcial del moderno Mercado de Pescados. A la derecha, el vecino y tambiâ”œآ®n novâ”œآ،simo inmueble edilicio del nâ”¬â•‘ 40 de la avenida. Fuente visual: www.delcampe.net', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65546900, -0.90589000, '0101000020E610000005C078060DFDECBF5A457F68E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45638708542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45638708542.webp', 'https://www.flickr.com/photos/zaragozaantigua/45638708542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23959, 'Cine Delicias 1974', 'Cine Delicias, construido en 1945 con proyecto de Teodoro Râ”œآ،os Balaguer en la avenida de Madrid nâ”¬â•‘ 147, en el solar del homâ”œâ”‚nimo cine proyectado en 1923 por Francisco Albiâ”œâ–’ana, que entre 1925 y 1944 fuera Cinema Espaâ”œâ–’a. En la imagen, marquesina del cine, clausurado en 1973. A la izquierda, la Escuela Nacional Emilio Moreno Calvete, y a la derecha, la "Fâ”œأ­brica de alambres y puntas de Parâ”œآ،s de Arribas Hermanos", esquinera con la calle de Sangenis.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65322600, -0.90489500, '0101000020E6100000A20BEA5BE6F4ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907444173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907444173.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907444173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24029, 'Mercado de Pescados 1960', 'Quiso la causalidad que el 18 de julio de ese aâ”œâ–’o fuera inaugurado el nuevo Mercado de Pescados de la ciudad, con diseâ”œâ–’o del arquitecto municipal Marcelo Carquâ”œآ® Aniesa, y ubicado en la avenida de Navarra, antigua de Caminreal. La imagen captura un emotivo momento de la iniciâ”œأ­tica ceremonia, cuando el plenario de autoridades civiles y militares estâ”œأ­ a punto de recibir el confesional, y tradicionalista, hisopazo. En primera lâ”œآ،nea de impacto, Antonio Zubiri Vidal, presidente de la DPZ; Josâ”œآ® Manuel Pardo de Santayana, recio gobernador civil; Luis Gâ”œâ”‚mez Laguna, alcalde; y Josâ”œآ® Lacalle Larraga, jefe de la regiâ”œâ”‚n aâ”œآ®rea pirenaica. Mâ”œأ­s resguardados, Juan Cabrera Felipe, rector de la Universidad; Gumersindo Claramunt Pastor, presidente del Banco Zaragozano, y algâ”œâ•‘n teniente de alcalde que otro, como Luis Ariâ”œâ–’o Malo. Las gafas de sol eran ese dâ”œآ،a una necesidad, no una falta de respeto, por supuesto. Unos aâ”œâ–’os despuâ”œآ®s, los exteriores de este moderno mercado aparecerâ”œآ،an en la pelâ”œآ،cula "Culpable para un delito", como escenario del nocturno deambular por un ficticio y portuario barrio chino. El mercado estuvo activo, como tal, hasta los aâ”œâ–’os 80, en que fue convertido en Centro Câ”œآ،vico del barrio de las Delicias. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65555100, -0.90662900, '0101000020E6100000AB5D13D21A03EDBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25351324512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25351324512.webp', 'https://www.flickr.com/photos/zaragozaantigua/25351324512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24793, 'Reloj de sol 2009', 'Foto: Josâ”œآ® Elâ”œآ،as. Trabajos de instalaciâ”œâ”‚n en Vadorrey del gnomon del mayor reloj solar del mundo, junto al parque de Oriente, el 30 de octubre de 2009. Se trata de una estructura de acero inoxidable de 46 metros, diseâ”œâ–’ada por Juan Antonio Ros. El proyecto incluâ”œآ،a el acondicionamiento del entorno, con fuentes, jardines y otras estructuras asociadas. En 2011 se colocâ”œâ”‚ la segmentaciâ”œâ”‚n horaria en el pavimento y en 2015 se aâ”œâ–’adiâ”œâ”‚ una esfera metâ”œأ­lica interpretativa. En 2017 se sigue a la espera de que la obra se complete, configurando la llamada plaza del Tiempo. En la imagen, al fondo, el barrio de la Jota, tras la calle del Marquâ”œآ®s de la Cadena. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'LAS FUENTES', 41.65420100, -0.86046500, '0101000020E6100000D4484BE5ED88EBBF5801BEDBBCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32441676234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32441676234.webp', 'https://www.flickr.com/photos/zaragozaantigua/32441676234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24034, 'Calle de Aragâ”œâ”‚n c.1942', 'Imagen capturada ante el antiguo nâ”¬â•‘ 1 de la calle de Aragâ”œâ”‚n, que desde 1937 habâ”œآ،a sido habilitado como provisional iglesia parroquial del barrio de las Delicias, dada la paralizaciâ”œâ”‚n de las obras de la iglesia de San Valero en la calle de Unceta. Las instalaciones de la imagen, casi esquineras con la avenida de Madrid (hacia la izquierda, fuera de plano), contaban con dependencias parroquiales en espacial cohabitaciâ”œâ”‚n con el grupo de la Juventud Catâ”œâ”‚lica Obrera del barrio, creado en 1934. Esta situaciâ”œâ”‚n se prolongâ”œâ”‚ hasta que a principios del aâ”œâ–’o 1947 fue inaugurada formalmente la nueva iglesia parroquial de San Valero, y unos aâ”œâ–’os antes, esta calle de Aragâ”œâ”‚n habâ”œآ،a sido ya redenominada de Don Alonso de Aragâ”œâ”‚n. Ninguno de los inmuebles de la imagen perdura. Fuente visual: La Crâ”œâ”‚nica de Zaragoza: Delicias-La Almozara.', 1942, 1942, 1942, 'Anos 40', 'DELICIAS', 41.65400600, -0.90330200, '0101000020E6100000202A8D98D9E7ECBFA3B1F677B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27230000798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27230000798.webp', 'https://www.flickr.com/photos/zaragozaantigua/27230000798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24169, 'Estaciâ”œâ”‚n de Caminreal 1933', 'El 2 de abril de 1933 se inaugurâ”œâ”‚ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza y enlazando a su vez con la lâ”œآ،nea internacional de Canfranc, reciâ”œآ®n inaugurada en 1928. El diseâ”œâ–’o y la ejecuciâ”œâ”‚n de la estaciâ”œâ”‚n de Ferrocarril Zaragoza-Delicias fue llevada a cabo por el arquitecto Luis Gutiâ”œآ®rrez Soto, siendo inaugurada en 1932. La estaciâ”œâ”‚n de ferrocarril Zaragoza-Delicias constituye el ejemplo mâ”œأ­s importante de las diversas estaciones construidas en la lâ”œآ،nea Zaragoza-Caminreal. Fuente visual: Archivo Asociaciâ”œâ”‚n Amigos del Ferrocarril.', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781164919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781164919.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781164919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24192, 'Estaciâ”œâ”‚n Caminreal 1933', 'Imagen de la celebrada llegada, desde Valencia, de los primeros viajeros de la lâ”œآ،nea de ferrocarril Caminreal-Zaragoza, en la primavera de 1933. Al fondo, la nueva Estaciâ”œâ”‚n terminal de lâ”œآ،nea, entre Almozara y Delicias. Delante de ella, la gran &quot;explanada de la Estaciâ”œâ”‚n&quot;, y la &quot;Entrada&quot; a la misma desde la carretera de Logroâ”œâ–’o a Zaragoza. La engalanada y festiva comitiva se dirige hacia la ciudad, que queda a la derecha. En las carrozas, las &quot;seâ”œâ–’oritas Miss Valencia, Miss Aragâ”œâ”‚n, Miss Huesca, la Fallera Mayor de Valencia, y la Matrona de la Repâ”œâ•‘blica&quot; camino de la Diputaciâ”œâ”‚n Provincial, a un sentido acto de confraternizaciâ”œâ”‚n entre el pueblo valenciano y el aragonâ”œآ®s. Fuente visual: Fot. Aldea, &quot;Mundo Grâ”œأ­fico&quot; (Madrid).', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65671300, -0.90989100, '0101000020E61000007097FDBAD31DEDBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21725304758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21725304758.webp', 'https://www.flickr.com/photos/zaragozaantigua/21725304758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24193, 'Estaciâ”œâ”‚n Delicias 1934', 'En abril de 1933 se inaugurâ”œâ”‚ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza, y enlazando a su vez por el norte con la lâ”œآ،nea internacional de Canfranc, inaugurada en 1928. En la imagen, la estaciâ”œâ”‚n terminal del "Ferrocarril Central de Aragâ”œâ”‚n", nombre comercial de la Compaâ”œâ–’â”œآ،a que gestionaba la lâ”œآ،nea, capturada desde la enorme explanada por la que se accedâ”œآ،a a ella desde la carretera de Logroâ”œâ–’o.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21905448916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21905448916.webp', 'https://www.flickr.com/photos/zaragozaantigua/21905448916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24856, 'Avenida de Madrid 1973', 'Imagen de la avenida de Madrid, a la altura de la calle Ramâ”œâ”‚n de Campoamor (izquierda) y Delicias (derecha), en las inmediaciones de la plaza de Huesca, capturada cuando un grupo de operarios procede al levantamiento de las vâ”œآ،as del tranvâ”œآ،a tendidas en la avenida, sin trâ”œأ­nsito desde su erradicaciâ”œâ”‚n de servicios previa. En 1969 ya fue suprimida la lâ”œآ،nea 14, Oliver, y a finales de 1971, en cumplimiento de la "terminator" hoja de ruta prevista, le tocâ”œâ”‚ a la lâ”œآ،nea 5, Venecia-Delicias. La prevista sustituciâ”œâ”‚n por autobuses urbanos con motor de explosiâ”œâ”‚n (que en algâ”œâ•‘n caso ya comenzâ”œâ”‚ en "vida activa" de algunas lâ”œآ،neas de tranvâ”œآ،a) queda reflejado en la imagen con una unidad de la lâ”œآ،nea 21, Plaza del Pilar-Oliver, en direcciâ”œâ”‚n a Oliver. Por su parte, la lâ”œآ،nea 5 del tranvâ”œآ،a fue sustituida por la lâ”œآ،nea 31 de bus, Venecia-Delicias, y la 32, Cuâ”œآ®llar-Delicias, sin aportar novedades en el trazado de la ruta. Grandes e indudables avances de la movilidad moderna, "ad maiorem vehiculi gloriam". Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65312400, -0.90608100, '0101000020E6100000FDDCD0949DFEECBFC91D369199D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31392485172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31392485172.webp', 'https://www.flickr.com/photos/zaragozaantigua/31392485172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24858, 'Pl. de Huesca 1974', 'Foto: Pilar Borobio. Vista de la plaza de Huesca, con la avenida de Madrid a la espalda y la calle de Leonardo Torres Quevedo al fondo. Un autobâ”œâ•‘s urbano de la lâ”œآ،nea 24 recoge a los pasajeros. Fuente: Heraldo de Aragâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65319100, -0.90662000, '0101000020E6100000DEC83CF20703EDBF51853FC39BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32042343840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32042343840.webp', 'https://www.flickr.com/photos/zaragozaantigua/32042343840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25932, 'Calle de Ramâ”œâ”‚n Campoamor 1955', 'Imagen capturada desde la avenida de Madrid y centrada en el desemboque desde la calle de Ramâ”œâ”‚n Campoamor de la composiciâ”œâ”‚n 112+102 (motor+remolque) en servicio en la tranviaria lâ”œآ،nea 5 "Venecia-Delicias". Aquâ”œآ، se encontraba la terminal en el barrio de Delicias de esta lâ”œآ،nea, en el entorno de la plaza de Rocasolano. Esta unidad motora de la serie de los "100" estuvo en servicio hasta la clausura de la lâ”œآ،nea en 1971, siendo transferida luego a la lâ”œآ،nea 1 "Bajo Aragâ”œâ”‚n", y desguazada en 1975 cuando esta fue tambiâ”œآ®n clausurada. Como telâ”œâ”‚n edilicio, y de izquierda a derecha, los antiguos inmuebles del nâ”¬â•‘ 84 de la avenida de Madrid y los nâ”œâ•‘meros 26, 24 y 22 de la calle de Ramâ”œâ”‚n Campoamor, todos ellos desaparecidos. A la derecha, mâ”œآ،nima visual del esquinero nâ”¬â•‘ 82 de la avenida de Madrid, que perdura como afortunada excepciâ”œâ”‚n a la norma. Fuente visual: foto Jordi Ibâ”œأ­â”œâ–’ez, en Los tranvâ”œآ،as de Zaragoza, Javier Peâ”œâ–’a Gonzalvo, Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, Zaragoza: DPZ, 1985.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65297600, -0.90697300, '0101000020E61000003A5CAB3DEC05EDBF5589B2B794D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41455524114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41455524114.webp', 'https://www.flickr.com/photos/zaragozaantigua/41455524114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26004, 'La Bombarda 1991', 'Foto: Archivo Taumar (Irene Taulâ”œآ®s y Rafael Margalâ”œآ®). Vista aâ”œآ®rea parcial del barrio de La Bombarda, con solares aâ”œâ•‘n sin edificar en primer tâ”œآ®rmino, y la confluencia de la calle Ramiro I de Aragâ”œâ”‚n con la avenida de Navarra (arriba a la izquierda). Arriba a la derecha, el barrio de Monsalud, tras el IES Fâ”œآ®lix de Azara. Fuente: www.facebook.com/photo.php?fbid=1687671944789838&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.65701600, -0.91586800, '0101000020E6100000637E6E68CA4EEDBF7079AC1919D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220301008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220301008.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220301008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26006, 'La Bombarda 1994', 'Foto: Archivo Taumar (Irene Taulâ”œآ®s y Rafael Margalâ”œآ®). Vista aâ”œآ®rea del barrio de La Bombarda, entre la avenida de Navarra (arriba) y la Vâ”œآ،a Hispanidad (abajo). Fuente: www.facebook.com/photo.php?fbid=1687674321456267&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65816300, -0.91965500, '0101000020E6100000CB4A9352D06DEDBFF83768AF3ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220881998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220881998.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220881998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
