INSERT INTO public.photos VALUES (22617, 'Calle de Galâ”œأ­n Bergua 1976', 'Urbanizaciâ”œâ”‚n de Las Delicias entre Los Enlaces y el Hospital Psiquiâ”œأ­trico. Centra la imagen el polâ”œآ®mico bloque de Construcciones Cinca S.A., levantado sin licencia de obra y contraviniendo ordenanzas municipales, luego legalizado a la carta. Al fondo, bloque sobre solar de la fâ”œأ­brica de Criado y Lorenzo. Tras â”œآ®l, la avenida de Madrid, y a su izquierda, esqueleto del bloque en construcciâ”œâ”‚n junto a Los Enlaces. En primer tâ”œآ®rmino, temporal paisaje lunar.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64832000, -0.91562000, '0101000020E61000005B087250C24CEDBFDEAB5626FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19310103081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19310103081.webp', 'https://www.flickr.com/photos/zaragozaantigua/19310103081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22747, 'Calle del Escultor Palao 1976', 'Imagen de la calle Escultor Palao en el "Polâ”œآ،gono 22", cuando era un sorprendente vial a tiempo parcial, pues parece ser que la empresa constructora "Criado y Lorenzo, SA" cerraba los portones al final de cada jornada, y los peatones y caminantes debâ”œآ،an buscar entonces otra ruta. Cosas de la Zaragoza de la â”œآ®poca. Lo mismo sucedâ”œآ،a en las inmediatas Roger de Flor, y Galâ”œأ­n Bergua. Tras la valla abierta con el sâ”œآ،mbolo "prohibido el paso", la calle Galâ”œأ­n Bergua. Al fondo, antiguos bloques inmediatos a la desaparecida fâ”œأ­brica de Criado y Lorenzo, luego derribados y sustituidos por otros mâ”œأ­s nuevos. Detrâ”œأ­s de ellos, a la derecha, emerge en obras el moderno bloque del nâ”¬â•‘ 96 de la Vâ”œآ،a Hispanidad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64859500, -0.91534000, '0101000020E61000007C0F971C774AEDBFB0AC342905D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32402673544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32402673544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32402673544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22769, 'Calle de Ramâ”œâ”‚n Salanova 1976', 'Imagen capturada desde la montaraz y agreste zona donde se trazarâ”œآ،a luego la prolongaciâ”œâ”‚n de Duquesa Villahermosa, con interesante visual del estado de las cosas en la zona suroeste del "Manicomio". A la izquierda, vista parcial de dos de los trillizos bloques de la novâ”œآ،sima calle de Ramâ”œâ”‚n Salanova. En el centro de la imagen, descampados varios para trâ”œأ­nsito peatonal, y aparcamiento, que se extienden hasta el muro perimetral del enorme espacio verde del Hospital Psiquiâ”œأ­trico de Nuestra Seâ”œâ–’ora del Pilar, del que emergen algunos de sus pabellones. Al fondo, estructuras de los nuevos bloques en construcciâ”œâ”‚n entre la calle de Barcelona, y la de Daroca. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64558000, -0.91245400, '0101000020E61000001D5723BBD232EDBFD1798D5DA2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33445685111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33445685111.webp', 'https://www.flickr.com/photos/zaragozaantigua/33445685111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22946, 'N.â”¬آ¬ S.â”¬آ¬ del Salz 1981', 'Campo del Club de Fâ”œâ•‘tbol Atlâ”œآ®tico Delicias, denominado de Nuestra Seâ”œâ–’ora de Guadalupe, y localizado entre las calles del Escultor Palao, de Nuestra Seâ”œâ–’ora del Salz (telâ”œâ”‚n de fondo edilicio de la imagen), de Terrer y de Demetrio Galâ”œأ­n Bergua. Este campo de tierra del barrio de Las Delicias estuvo activo hasta que en 1983 el planeamiento urbanâ”œآ،stico ubicâ”œâ”‚ en este emplazamiento el Colegio Pâ”œâ•‘blico Ciudad de Zaragoza y el homâ”œâ”‚nimo Pabellâ”œâ”‚n Deportivo Municipal. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1981, 1981, 1981, 'Anos 80', 'DELICIAS', 41.64850400, -0.91474000, '0101000020E61000002FFA0AD28C45EDBFA0A9D72D02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38486173246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38486173246.webp', 'https://www.flickr.com/photos/zaragozaantigua/38486173246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23698, 'Calle de Terrer 1977', 'Escena nival capturada desde el bloque de la calle de Barcelona, tramo actualmente denominado calle de la Villa de Andorra, esquinero con la calle de Sigâ”œâ•‌â”œآ®s, y centrada en los inmuebles de los nâ”œâ•‘meros 2-4 de la calle de Terrer, en cuyos bajos y desde 1972 destaca el Centro Comercial Delicias, mercado de proximidad que perdura. Ante â”œآ®l pasa un autobâ”œâ•‘s urbano de la lâ”œآ،nea 31. Torrero-Delicias. En el solar de primer tâ”œآ®rmino, ocupado por camiones, serâ”œأ­ construido luego el Centro de Salud Universitas. A la izquierda, la calle de Nuestra Seâ”œâ–’ora del Salz, donde destaca el Campo de Nuestra Seâ”œâ–’ora de Guadalupe para la prâ”œأ­ctica futbolâ”œآ،stica, hasta que en 1983 el planeamiento urbanâ”œآ،stico de la zona dedicâ”œâ”‚ estos terrenos para el Colegio Pâ”œâ•‘blico Ciudad de Zaragoza y el homâ”œâ”‚nimo Pabellâ”œâ”‚n Deportivo Municipal. Mâ”œأ­s allâ”œأ­, bloques de la calle de Demetrio Galâ”œأ­n Bergua.', 1977, 1977, 1977, 'Anos 70', 'DELICIAS', 41.64736600, -0.91368600, '0101000020E61000008E041A6CEA3CEDBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15808433362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15808433362.webp', 'https://www.flickr.com/photos/zaragozaantigua/15808433362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23727, 'Galâ”œأ­n Bergua 1978', 'Irrepetible imagen centrada en el montaraz barbecho urbanâ”œآ،stico de la calle Demetrio Galâ”œأ­n Bergua, en el tramo delimitado por las calles de Fray Juan Regla (tras los bloques del fondo), y la del Escultor Palao. Las parcelas de la derecha, recayentes a la calle de Nâ”¬آ¬ Sâ”¬آ¬ del Salz, incluyendo el enternecedor acceso a las parcelitas del nâ”¬â•‘ 10 A, B, C, D, y E de esa calle, perduran de forma prodigiosa. La terrosa pista de primer plano, por la que caminan algunos vecinos se convertirâ”œأ­, al tiempo, en la acera de acceso a los modernos bloques de los nâ”œâ•‘meros 11-21 de Galâ”œأ­n Bergua. Fuente visual: Banco de Imâ”œأ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œآ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.64933200, -0.91571500, '0101000020E6100000CB9C2E8B894DEDBF861F9C4F1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32348482514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32348482514.webp', 'https://www.flickr.com/photos/zaragozaantigua/32348482514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21226, 'Caballos en el Ebro 1905', '"Partida de la balsa", fotografâ”œآ،a del teniente Eladio Pascual, 1905. Imagen perteneciente al reportaje "Prâ”œأ­cticas de paso de râ”œآ،os realizadas por el Regimiento Lanceros del Rey, 1â”¬â•‘ de Caballerâ”œآ،a". En este caso, se trata de pasar de una orilla a otra del Ebro, mediante una balsa construida con sacas rellenas de paja. Los caballos atravesaron el râ”œآ،o a nado. Al fondo parece vislumbrarse la silueta del Pilar. La zona donde se realizan las maniobras es, probablemente, aguas abajo, entre las desembocaduras de los râ”œآ،os Gâ”œأ­llego y Huerva, que tambiâ”œآ®n fueron objeto de prâ”œأ­cticas militares en este mismo conjunto de ejercicios. Fuente: Revista La ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana, 15-9-1905. hemerotecadigital.bne.es/', 1905, 1905, 1905, 'Anos 1900', 'LAS FUENTES', 41.65237400, -0.86017500, '0101000020E610000011C7BAB88D86EBBF5F61C1FD80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18465102323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18465102323.webp', 'https://www.flickr.com/photos/zaragozaantigua/18465102323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23741, 'Calle de N.â”¬آ¬ S.â”¬آ¬ del Salz 1976', 'Imagen capturada a la altura del nâ”œâ•‘mero 41 de la calle de N.â”¬آ¬ S.â”¬آ¬ del Salz y centrada en una singular pintada que proclama "â”¬أ­Viva el alcalde!" y aparece firmada por la no menos singular facciâ”œâ”‚n ultraderechista "Alianza anticomunista/anticapitalista", como forma de respaldar al regidor Miguel Merino Pineda en el denominado "conflicto de las vallas", cuando durante la urbanizaciâ”œâ”‚n del Polâ”œآ،gono 22 (terrenos de la antigua fâ”œأ­brica de Criado y Lorenzo) la empresa constructora "CYLSA" (Criado y Lorenzo, SA) cerraba los portones de obra al final de cada jornada que permitâ”œآ،an el paso por el recinto vallado de unos 50.000 metros cuadrados, cortando asâ”œآ، los pasos usados por los peatones que debâ”œآ،an buscar otra ruta dando enorme rodeo. En primer tâ”œآ®rmino, un SEAT 124, y al fondo la esquina con la calle del Escultor Palao.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64857600, -0.91450400, '0101000020E610000038F581E49D43EDBF397CD28904D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54252959002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54252959002.webp', 'https://www.flickr.com/photos/zaragozaantigua/54252959002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25980, 'Delicias 1968', 'Desde las once alturas del nâ”¬â•‘ 9 de la calle de Demetrio Galâ”œأ­n Bergua, panorâ”œأ­mica del barrio de Las Delicias. En primer tâ”œآ®rmino, la calle de Nuestra Seâ”œâ–’ora del Salz, con detalle del nâ”¬â•‘ 16, en contrucciâ”œâ”‚n, y del singular acceso a las fincas A, B, C y D del nâ”¬â•‘ 8, y las A, B, C, D, y E del nâ”¬â•‘ 10. Detrâ”œأ­s, la calle de Mosâ”œآ®n Andrâ”œآ®s Vicente, cruzada de izquierda a derecha por las calles de Fray Luis Regla, de Antonio Bravo, de Eloy Martâ”œآ،nez, y del Escultor Palao. Aâ”œâ–’os despuâ”œآ®s, algunos inmuebles de esta calle serâ”œآ،an sustituidos por bloques mâ”œأ­s altos, como en el caso de los nâ”œâ•‘meros 12-14, 18, y 20. A la derecha, traseras de los bloques de la plaza, actual calle, de la Ciudadela, que eclipsan a los norteâ”œâ–’os pabellones de Dronda, y de Santa Ana, del Hospital Psiquiâ”œأ­trico Nuestra Seâ”œâ–’ora del Pilar. Al fondo, la perspectiva permite ver las cuatro torres del Pilar, con la câ”œâ•‘pula mayor en medio. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64736100, -0.91414300, '0101000020E610000027C11BD2A840EDBF59DAA9B9DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236729062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236729062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236729062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21534, 'Barrio de la Romareda 1927', 'Panorâ”œأ­mica del barrio de la Romareda. Este conjunto conformâ”œâ”‚, con otros similares adyacentes, el actual barrio de Las Delicias. Se situâ”œâ”‚ en traseras de la Estaciâ”œâ”‚n de Campo Sepulcro, en la parte comprendida entre las actuales avenidas de Valencia y Madrid. Tomaba su nombre de la acequia alta de la Romareda. Fuente visual de la imagen: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19472107288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19472107288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19472107288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
