INSERT INTO public.photos VALUES (21912, 'Campo Sepulcro 1939', 'Imagen capturada en el gran complejo fabril de la empresa Material Mâ”œâ”‚vil y Construcciones sita al oeste de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro y centrada en la ceremonia de la "Fiesta de la exaltaciâ”œâ”‚n del Trabajo" instituida por el Fuero del Trabajo y que se debâ”œآ،a celebrar obligatoriamente el 18 de julio coincidiendo con el aniversario del "Glorioso Alzamiento Nacional". Esta fiesta respondâ”œآ،a al "nuevo" concepto del trabajo como "fiesta de la hermandad y de la unidad de los productores incorporada en la alegrâ”œآ،a unâ”œأ­nime de la Patria al festejar el 18 de julio". De esa forma, los "productores" tenâ”œآ،an que celebrar ese dâ”œآ،a "en agrupaciâ”œâ”‚n ordenada", reunidos en sus respectivas empresas y dispuestos "conforme a la jerarquâ”œآ،a natural de la producciâ”œâ”‚n" en lugar presidido por la Bandera Nacional, las del "Movimiento" y el retrato del "Caudillo" en sitio de honor, y si fuera posible, con mâ”œâ•‘sica de los respectivos himnos. Cerraban la fiesta los gritos reglamentarios de "ESPAâ”œأ¦A, UNA; ESPAâ”œأ¦A, GRANDE; ESPAâ”œأ¦A, LIBRE; â”¬أ­ARRIBA ESPAâ”œأ¦A!" En la imagen, vista en altura del momento en que los "productores", dispuestos en el gran pasillo central flanqueado por las naves y talleres de esta empresa, saludan con el reglamentario brazo en alto a la enseâ”œâ–’a nacional que preside el acto. Al fondo, traseras de la larga calle de Roche y campos de cultivo que flanquean la carretera de Zaragoza a Valencia hasta los pabellones del cuartel de Palafox.', 1939, 1939, 1939, 'Anos 30', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52156383140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52156383140.webp', 'https://www.flickr.com/photos/zaragozaantigua/52156383140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22181, 'Calle Escosura 1959', 'Imagen aâ”œآ®rea sobrevolando el antiguo entorno, en primer tâ”œآ®rmino, de las calles Escosura, Tarragona y â”œأ¼vila, para obtener una buena perspectiva del complejo fabril de Material Mâ”œâ”‚vil y Construcciones, junto a la estaciâ”œâ”‚n de Campo Sepulcro y el barrio de Cariâ”œâ–’ena, a la derecha. A la izquierda, indefinido enlace con el barrio de Delicias. Al fondo, la Aljaferâ”œآ،a y la Almozara. Fuente visual: fondo fotogrâ”œأ­fico TAF Helicâ”œâ”‚pteros SA , en Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.64892300, -0.89843100, '0101000020E61000006CCD565EF2BFECBFA54FABE80FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31895640275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31895640275.webp', 'https://www.flickr.com/photos/zaragozaantigua/31895640275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22249, 'Barrio de la Romareda 1956', 'Imagen capturada desde la altura de las nuevas naves seriadas de los talleres de Material Mâ”œâ”‚vil y Construcciones, S.A. en terrenos inmediatos al antiguo barrio de la Romareda, que a la izquierda se presenta arbolado y vertebrado por las calles del Moncayo y la antigua de Gascâ”œâ”‚n, actual de Escoriaza. Al fondo, inmuebles de la calles de Salamanca, Tarragona, â”œأ¼vila y Escosura.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65070900, -0.89667300, '0101000020E6100000429946938BB1ECBF3F1BB96E4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52321858824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52321858824.webp', 'https://www.flickr.com/photos/zaragozaantigua/52321858824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21544, 'Reformatorio Buen Pastor 1921', 'Dibujo de Regino Borobio del Reformatorio del Buen Pastor de Zaragoza, 1921. La Torre Ramona se acondicionâ”œâ”‚ para reformatorio en 1917 y dejâ”œâ”‚ de funcionar como tal en 1955. Tras funcionar como colegio de monjas, el edificio sigue en pie en la calle de Marâ”œآ،a de Aragâ”œâ”‚n del barrio de Las Fuentes en 2015. Fuente: Eloy Fernâ”œأ­ndez Clemente, "Gente de orden", Ibercaja, 1995.', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20124614286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20124614286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20124614286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22252, 'Campo Sepulcro 1953', 'Imagen capturada en el interior de una de las naves de la factorâ”œآ،a de Material Mâ”œâ”‚vil y Construcciones sita en el barrio de Cariâ”œâ–’ena o de la Romareda, junto a la estaciâ”œâ”‚n de Campo Sepulcro. La escena se centra en uno de los dos chasis del microcoche "Pulga" aquâ”œآ، carrozado, una versiâ”œâ”‚n mâ”œأ­s moderna del original proyecto mallorquâ”œآ،n patentado en 1950 y desarrollado en Ontinent (Valencia). Los microcoches o coches diminutos, algunos de ellos sustentados sobre tres ruedas como este "Pulga", conocieron un singular desarrollo en la Espaâ”œâ–’a de la larga posguerra (aâ”œâ–’os 50 y 60), siendo este modelo "Pulga" uno de los pioneros, si bien su producciâ”œâ”‚n fue muy modesta. Tras el vehâ”œآ،culo de primer tâ”œآ®rmino, uno de los vagones ferroviarios fabricados en esta fâ”œأ­brica.', 1953, 1953, 1953, 'Anos 50', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54723497577.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54723497577.webp', 'https://www.flickr.com/photos/zaragozaantigua/54723497577/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22262, 'Trolebâ”œâ•‘s 1966', '1966. El Trolebâ”œâ•‘s 51 de la Lâ”œآ،nea "Ciudad Jardâ”œآ،n" haciendo la curva que desde Franco y Lâ”œâ”‚pez le permite seguir por Duquesa de Villahermosa para llegar a su destino en la Ciudad Jardâ”œآ،n, dar la vuelta en la calle Pedro de Luna, y coger San Juan Bosco para retornar a la Terminal de la Plaza de Santa Engracia. En primer tâ”œآ®rmino, un taxi caracterâ”œآ،stico de la â”œآ®poca en Zaragoza. A la izquierda, el Colegio de las "Josefinas" (Hijas de San Josâ”œآ®). Al fondo, las naves del inmenso polâ”œآ،gono de Carde y Escoriaza, que llegaban hasta lo que luego, ya urbanizada, serâ”œأ­ la Plaza de Roma', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14788184428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14788184428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14788184428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22335, 'Calle Santander 1969', 'Pintura de Eduardo Laborda titulada "La calle Santander de Zaragoza". Posiblemente se trate del nuevo bloque de viviendas del nâ”¬â•‘ 32, esquina con la calle Josâ”œآ® Pascasio Escoriaza, tan chocante con el hasta entonces mâ”œأ­s humano en escala entorno de la antigua estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, con sus parcelas, huertos traseros... Al fondo, tal vez los bloques de las viviendas militares de Anselmo Clavâ”œآ®, frente a la estaciâ”œâ”‚n. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajalâ”œâ”‚n, 2006.', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64916200, -0.89666200, '0101000020E6100000471CB28174B1ECBF29E78BBD17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19537993041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19537993041.webp', 'https://www.flickr.com/photos/zaragozaantigua/19537993041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22564, 'Plaza de Roma 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 08/09/1974. Los sucesivos proyectos de "Casas Baratas" y de ordenaciâ”œâ”‚n urbanâ”œآ،stica del crecimiento de la ciudad por el oeste dejaron pocas realidades en la zona del original barrio de la Romareda, o de Cariâ”œâ–’ena, salvo la aislada intervenciâ”œâ”‚n de la "Ciudad Jardâ”œآ،n". Habâ”œآ،a demasiados intereses especulativos en su contra y, ademâ”œأ­s, la omnipotente presencia del enorme complejo fabril de Escoriaza, en las traseras de Campo Sepulcro, condicionaba cualquier actuaciâ”œâ”‚n. Cuando esta fâ”œأ­brica se deslocalizâ”œâ”‚ a otra ubicaciâ”œâ”‚n, se abrieron nuevas calles, y la urbanizaciâ”œâ”‚n de la zona (grandes bloques de viviendas) avanzâ”œâ”‚ râ”œأ­pidamente al albur del desarrollismo sesentero. Asâ”œآ،, la plaza de Roma y la estratâ”œآ®gica Urbanizaciâ”œâ”‚n Parque Roma vieron la luz en fecha tan reciente como 1972, en un entorno irreconocible para quien recordara el paso del antiguo ferrocarril de Cariâ”œâ–’ena justo aquâ”œآ،. En la imagen, la plaza de Roma vista en altura, con la calle Vicente Berdusâ”œأ­n a la derecha, luego la calle Italia, y el arranque, a la izquierda, de Duquesa Villahermosa.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.64948200, -0.89899000, '0101000020E610000014CB2DAD86C4ECBF9BABE63922D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231545788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231545788.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231545788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22585, 'Calle Delicias c.1973', 'Vista de la calle Delicias de Zaragoza desde su embocadura en la calle Duquesa Villahermosa. A la izquierda, colegio pâ”œâ•‘blico Andrâ”œآ®s Manjâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1680995642145619&set=...', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64792500, -0.90372300, '0101000020E61000008693347F4CEBECBF62A1D634EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15647214881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15647214881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15647214881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22599, 'D. Pedro de Luna 1975', 'El denominado "Dâ”œآ،a del Ahorro", celebrado a bombo y platillo como si de un ejercicio de participaciâ”œâ”‚n democrâ”œأ­tica en la economâ”œآ،a se tratara, era sin embargo algo mâ”œأ­s pedestre, y menos revolucionario: un puro ejercicio de captaciâ”œâ”‚n del ahorro de los pobres por parte de las entidades gestoras del dinero ajeno que, a cambio, "regalaban" libros sobre recuerdos regionalistas entraâ”œâ–’ables y amables, algunos sesudos libros de historia para decorar estanterâ”œآ،as, frescas colonias de garrafâ”œâ”‚n, et cetera. De esta forma, y otras mâ”œأ­s, la entidad de ahorro que aparece en la imagen consiguiâ”œâ”‚ cuatriplicar sus recursos ajenos en pocos aâ”œâ–’os, convirtiâ”œآ®ndose en la tercera de las Cajas Confederadas espaâ”œâ–’olas. Otro asunto muy distinto era en quâ”œآ® invertâ”œآ،a luego esos dineros, siquiera si lo hacâ”œآ،a en la "regiâ”œâ”‚n aragonesa" (y Rioja, por supuesto), y con quâ”œآ® resultados. En la imagen, una de las filas, o "colas" que se organizaban a la entrada de estas entidades de ahorro en esos dâ”œآ،as tan seâ”œâ–’alados, de "fiesta del ahorro". La clase social de quienes forman la cola es esa que estâ”œأ­ acostumbrada a hacer cola siempre, incluso para dar su dinero a un interâ”œآ®s ridâ”œآ،culo, o a cambio de un libro de cocina. Estamos en la que fuera calle de Josâ”œآ® Arias, luego denominada D. Pedro de Luna, casi en la esquina con el antiguo Camino de la Mosquetera y la acequia de la Romareda, luego Duquesa Villahermosa. La agencia de la entonces caja, hoy banco, sigue en el mismo sitio. Lo que ha desaparecido es el edificio de ladrillo de su izquierda. Fuente: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.64822400, -0.90329200, '0101000020E61000003CA1D79FC4E7ECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18582357213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18582357213.webp', 'https://www.flickr.com/photos/zaragozaantigua/18582357213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22742, 'Calle de Vicente Berdusâ”œأ­n 1973', 'A lomos de un mulo, un avezado jinete (el detalle del modelo de calzado que gasta lo delata) cruza con resoluciâ”œâ”‚n por el final de la calle de Vicente Berdusâ”œأ­n y se encamina hacia la calle de la Duquesa de Villahermosa. De fondo, portal de ingreso al moderno bloque esquinero del nâ”¬â•‘ 24 de Vicente Berdusâ”œأ­n, actual nâ”¬â•‘ 46. A la izquierda, local reservado para instalar una sucursal de la Caja de Ahorros de la Inmaculada. A la derecha, local comercial donde aâ”œâ–’os despuâ”œآ®s se constituirâ”œأ­ la Ferreterâ”œآ،a Arias. A espaldas del fotâ”œâ”‚grafo, el antiguo y gran complejo industrial de Material Mâ”œâ”‚vil y Construcciones, ya redenominada Construcciones y Auxiliar de Ferrocarriles, y en proceso de reubicaciâ”œâ”‚n en unas nuevas instalaciones en la avenida de Cataluâ”œâ–’a.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64983700, -0.89894600, '0101000020E61000002CD7DB662AC4ECBF895DDBDB2DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800517187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800517187.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800517187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22751, 'Calle de Escosura 1976', 'Imagen del calificado como "â”œâ•‘ltimo â”œأ­rbol de Escosura", que tambiâ”œآ®n fue finalmente arrancado durante las obras de vialidad y aguas que tras varios meses renovaron el abastecimiento y saneamiento de esta antigua calle, antes denominada de Roche. El â”œأ­rbol estaba ubicado a la altura del nâ”¬â•‘ 38-B, en la imagen flanqueado por dos parcelas luego sustituidas por modernos edificios. Hacia la derecha, direcciâ”œâ”‚n avenida de Valencia. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64798500, -0.89842000, '0101000020E61000007250C24CDBBFECBF37A6272CF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32611850383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32611850383.webp', 'https://www.flickr.com/photos/zaragozaantigua/32611850383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23041, 'Calle de Vicente Berdusâ”œأ­n 1994', 'Imagen capturada durante la urbanizaciâ”œâ”‚n de la calle de Vicente Berdusâ”œأ­n y el tramo de la calle de Escoriaza y Fabro comprendido entre esta calle y la avenida de Madrid. En primer tâ”œآ®rmino, vehâ”œآ،culos aparcados sobre los solares de antiguas parcelas derribadas entre las calles de Româ”œأ­n Izuzquiza y de Fuendetodos, donde a finales de esta dâ”œآ®cada se construirâ”œآ،a el actual inmueble del nâ”¬â•‘ 30 de la calle de Vivente Berdusâ”œأ­n. Hacia el fondo y a la izquierda, bloques de viviendas del camino de la Mosquetera y de las calles de Hilariâ”œâ”‚n Eslava. Navas de Tolosa y Doâ”œâ–’a Blanca de Navarra. Al fondo, bloques de la calle de Fuenterrabâ”œآ،a. A la derecha, bloques de la urbanizaciâ”œâ”‚n Parque Roma. La urbanizaciâ”œâ”‚n de esta zona incluâ”œآ،a la renovaciâ”œâ”‚n del servicio de alcantarillado para resolver las crâ”œâ”‚nicas deficiencias de evacuaciâ”œâ”‚n de aguas pluviales que se acumulaban en el paso a desnivel de la avenida de Madrid.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65087700, -0.89879700, '0101000020E6100000EFC517EDF1C2ECBFFB5B02F04FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380195132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380195132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380195132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23122, 'Vâ”œآ،a Univâ”œآ®rsitas 2006', 'Foto: Marâ”œآ،a Torres-Solanot. Construcciâ”œâ”‚n del Centro Câ”œآ،vico Esquinas del Psiquiâ”œأ­trico, en la Vâ”œآ،a Univâ”œآ®rsitas 30-32. En 2003 fueron adjudicadas las obras de este entorno por parte del Gobierno de Aragâ”œâ”‚n al grupo Bruesa. Los equipamientos municipales incluidos fueron un pabellâ”œâ”‚n polideportivo, un teatro y este centro, inaugurado en 2010. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.64679300, -0.90780100, '0101000020E6100000C7D5C8AEB40CEDBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31130296583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31130296583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31130296583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23317, 'Plaza de Roma 1968', '1968. Familia Roldâ”œأ­n. "Gravera (Plaza Roma) vista desde la C/ Italia". La urbanizaciâ”œâ”‚n del polâ”œآ،gono industrial de Carde y Escoriaza en las traseras de la Estaciâ”œâ”‚n Campo Sepulcro iba a suponer que la ciudad tuviera una "Plaza de Roma" modelada como eje entre Duquesa Villahermosa, y las nuevas calles de Santander y Vicente Berdusâ”œأ­n, ademâ”œأ­s de propiciar el crecimiento de altos y modernos bloques residenciales. En la imagen, familiar posado a la entrada de la calle Desiderio Escosura, desde lo que mâ”œأ­s tarde serâ”œأ­ la Plaza de Roma, con el enorme bloque de entrada a la calle en plena construcciâ”œâ”‚n. Al fondo, el no menos impresionante Edificio Torresol. A la izquierda, insâ”œâ”‚lita vista de las calles Tarragona y â”œأ¼vila. Antes, restos piqueteados de las naves de Carde y Escoriaza, utilizados como parque infantil de juego, como pasaba en todos los barrios de la periferia de la ciudad, sin que aparentemente ninguna madre entrara en coma.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64898500, -0.89908700, '0101000020E6100000B247A81952C5ECBF1B4CC3F011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14783752810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14783752810.webp', 'https://www.flickr.com/photos/zaragozaantigua/14783752810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23693, 'Hospital Psiquiâ”œأ­trico 1964', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 4/7/1964. Instalaciones del Hospital Psiquiâ”œأ­trico Nuestra Seâ”œâ–’ora del Pilar de Zaragoza (manicomio). Al fondo, la capilla que aâ”œâ•‘n se levanta en el parque. En primer plano, busto con arbusto de D. Manuel Dronda, prâ”œâ”‚cer local fallecido el 1 de diciembre de 1899, que habâ”œآ،a dedicado tiempo y fortuna a la mejora del manicomio, comprando terrenos y mandando construir pabellones. La DPZ acordâ”œâ”‚ que a su cadâ”œأ­ver se le hiciera una mascarilla funeraria (por el escultor Palao) para un busto fundido en metal que honrara su memoria en lugar principal del establecimiento.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.64685600, -0.91068400, '0101000020E6100000E2B19FC55224EDBF569C6A2DCCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024451200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024451200.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024451200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23702, 'San Simeâ”œâ”‚n, o los Gigantes en el manicomio 1925', 'Se estiman en unos 400 los tipos de trastornos mentales que acompaâ”œâ–’an al ser humano en su trâ”œأ­nsito por este valle de lâ”œأ­grimas. Entre los mâ”œأ­s comunes se encuentran los trastornos afectivos (depresiones y distimias), de ansiedad (fobias, angustias, obsesivos compulsivos, somatizaciâ”œâ”‚n ...), adicciones (innâ”œâ•‘meras), trastornos psicâ”œâ”‚ticos (esquizofrenia, bipolaridad ...), y aquellos asociados a la tercera edad (demencias, trastornos del sueâ”œâ–’o ...) A pesar de sus enormes complejidades, la "locura", como simplificaciâ”œâ”‚n extrema del asunto, es interpretada culturalmente como un defecto, un estigma: loco es quien ha perdido la razâ”œâ”‚n. Desde que en la edad media se pretendâ”œآ،a sanar al loco mediante la "extracciâ”œâ”‚n de la piedra de la locura", o cirugâ”œآ،a mayor, han sido varias las estrategias de las polâ”œآ،ticas pâ”œâ•‘blicas a la hora de afrontar este tema, aunque la mâ”œأ­s generalizada ha sido la asociada con el estigma que le acompaâ”œâ–’a: poner al loco fuera de circulaciâ”œâ”‚n como medida de saneamiento social, y recluirlo en un hospital, junto a los pobres. Hasta que en 1914 se desarrolla la enfermerâ”œآ،a mental de carâ”œأ­cter laico, y en los aâ”œâ–’os 20 se crea la Escuela Nacional de Sanidad y la Escuela de Psiquiatrâ”œآ،a, los tratamientos consistâ”œآ،an en un internado donde se velaba por la salud corporal, la alimentaciâ”œâ”‚n y la educaciâ”œâ”‚n en la doctrina cristiana. En Zaragoza, la DPZ acordâ”œâ”‚ construir segâ”œâ•‘n estos preceptos, en 1873, un Manicomio Modelo en la Granja de Nâ”¬آ¬. Sâ”¬آ¬. del Pilar, en el Terminillo. Hasta entonces, los asilados estaban ingresados en el Hospital de Gracia. Una vez terminados, los nuevos pabellones tenâ”œآ،an capacidad para 600 enfermos, con casi 4 hectâ”œأ­reas de buena huerta alrededor. En 1912 este Manicomio pasâ”œâ”‚ a depender del Estado. En la imagen, el Rey y la Reina encabezan la tradicional comparsa de Gigantes en los jardines y pabellones del Manicomio, para fiestear a los internos. â”œأ«stos observan atentamente a los inanimados artefactos despojados de sus titiriteros, mientras que uno de ellos pref', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.64690100, -0.91150000, '0101000020E61000005EBA490C022BEDBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18484244615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18484244615.webp', 'https://www.flickr.com/photos/zaragozaantigua/18484244615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
