INSERT INTO public.photos VALUES (23705, 'Calle Sangenâ”œآ،s 1924', 'Acceso de los Talleres Chalmeta en 1924. Fundados en 1919, producâ”œآ،an envases metâ”œأ­licos, artâ”œآ،culos de hojalaterâ”œآ،a y estampaciones sobre metales. Estaban situados en la calle de Antonio Sangenâ”œآ،s 40 del barrio de las Delicias. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65013000, -0.90335800, '0101000020E6100000198F52094FE8ECBF0113B87537D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19845170688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19845170688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19845170688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23707, 'Isabel de Borbâ”œâ”‚n 1913', 'Visita de la infanta Isabel de Borbâ”œâ”‚n, "la Chata", hija de la reina Isabel II, al Manicomio de Zaragoza en julio de 1913. Le acompaâ”œâ–’an el prior del Manicomio de Nuestra Seâ”œâ–’ora del Pilar, la superiora y el mâ”œآ®dico director, dr. Gimeno Riera. Fuente: Fotografâ”œآ،a de Aurelio Grasa publicada en el libro "Aurelio Grasa 1893-1972", Galerâ”œآ،a Costa, 3, 1976. Pâ”œأ­gina 37. Formâ”œâ”‚ parte de la exposiciâ”œâ”‚n conmemorativa celebrada en dicha galerâ”œآ،a en 1978. Tambiâ”œآ®n fue publicada en la pâ”œأ­gina 53 del catâ”œأ­logo "Aurelio Grasa reportero grâ”œأ­fico 1910-1917", RSFZ, Galerâ”œآ،a Costa,3. Zaragoza 2003. Fotografia publicada en Heraldo de Aragâ”œâ”‚n el 23 de julio de 1913, en ABC el 25 de julio de 1913. El periâ”œâ”‚dico ABC conserva una copia de esa fotografâ”œآ،a de Aurelio Grasa que el mismo enviâ”œâ”‚ para su publicaciâ”œâ”‚n. www.aureliograsa.es', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64716400, -0.91050300, '0101000020E6100000CD1DFD2FD722EDBF03931B45D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21280020406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21280020406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21280020406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
